#include <iostream>#include <vector>#include <algorithm>#include <cmath>#include <string>#include <map>#include <set>#include <iomanip>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n;    cin >> n;    vi arr(n);    for (int i = 0; i < n; i++) {        cin >> arr[i];    }    int pos_count = 0;    int neg_count = 0;    int answer = 0;    for (int i = 0; i < n; i++) {        if (arr[i] == 1) {            pos_count++;        } else {            neg_count++;        }    }    while(pos_count<neg_count || neg_count%2 ==1){        answer++;        pos_count++;        neg_count--;    }    cout << answer << "\n";} // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}